import React, { useState, useEffect } from 'react';
import axios from 'axios';
import Navbar from '../components/Navbar';
import PostCard from '../components/PostCard';
import RightSidebar from '../components/RightSidebar';
import { useAuth } from '../context/AuthContext';

export default function HomePage() {
  const { user } = useAuth();
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchFeed();
  }, []);

  const fetchFeed = async () => {
    try {
      const { data } = await axios.get('/api/posts/feed');
      setPosts(data);
    } catch (err) {
      console.error('Failed to fetch feed', err);
    } finally {
      setLoading(false);
    }
  };

  const handleNewPost = (post) => {
    setPosts(prev => [post, ...prev]);
  };

  return (
    <div style={styles.page}>
      <Navbar onNewPost={handleNewPost} />

      <div style={styles.layout}>
        {/* Feed */}
        <main style={styles.feed}>
          {loading ? (
            <div style={styles.loading}>
              {[1,2,3].map(i => <PostSkeleton key={i} />)}
            </div>
          ) : posts.length === 0 ? (
            <div style={styles.empty}>
              <svg viewBox="0 0 24 24" width="64" height="64" fill="none" stroke="#dbdbdb" strokeWidth="1">
                <rect x="3" y="3" width="18" height="18" rx="2"/>
                <circle cx="8.5" cy="8.5" r="1.5"/>
                <polyline points="21 15 16 10 5 21"/>
              </svg>
              <h3 style={{ marginTop: 16, color: '#262626' }}>No Posts Yet</h3>
              <p style={{ color: '#8e8e8e', marginTop: 8 }}>Start by creating your first post!</p>
            </div>
          ) : (
            posts.map(post => (
              <PostCard key={post.id} post={post} currentUser={user} />
            ))
          )}
        </main>

        {/* Right Sidebar */}
        <aside style={styles.sidebar}>
          <RightSidebar />
        </aside>
      </div>
    </div>
  );
}

function PostSkeleton() {
  return (
    <div style={{ background: '#fff', border: '1px solid #dbdbdb', borderRadius: 8, marginBottom: 24, overflow: 'hidden' }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '12px 16px' }}>
        <div style={{ width: 32, height: 32, borderRadius: '50%', background: '#efefef' }} />
        <div style={{ width: 100, height: 12, borderRadius: 4, background: '#efefef' }} />
      </div>
      <div style={{ width: '100%', height: 300, background: '#efefef' }} />
      <div style={{ padding: 16 }}>
        <div style={{ width: 80, height: 12, borderRadius: 4, background: '#efefef', marginBottom: 8 }} />
        <div style={{ width: '60%', height: 12, borderRadius: 4, background: '#efefef' }} />
      </div>
    </div>
  );
}

const styles = {
  page: { background: '#fafafa', minHeight: '100vh' },
  layout: {
    maxWidth: 975,
    margin: '0 auto',
    paddingTop: 80,
    paddingLeft: 20,
    paddingRight: 20,
    display: 'flex',
    gap: 28,
    alignItems: 'flex-start',
  },
  feed: { flex: 1, minWidth: 0, maxWidth: 614 },
  sidebar: { flexShrink: 0, width: 319, position: 'sticky', top: 80 },
  loading: {},
  empty: { textAlign: 'center', padding: '80px 20px', display: 'flex', flexDirection: 'column', alignItems: 'center' },
};
